from dataclasses import dataclass
from datetime import datetime
from typing import Dict, List

@dataclass
class PurchaseOrder:
    order_id: str
    customer_id: str
    order_date: datetime
    items: List[Dict[str, any]]
    total_amount: float
    status: str

# Predefined dictionary of purchase orders
purchase_orders = {
    "PO-001": PurchaseOrder(
        order_id="PO-001",
        customer_id="CUST-123",
        order_date=datetime(2024, 1, 15, 10, 30),
        items=[
            {"product_id": "PROD-A", "quantity": 2, "price": 29.99},
            {"product_id": "PROD-B", "quantity": 1, "price": 49.99}
        ],
        total_amount=109.97,
        status="completed"
    ),
    "PO-002": PurchaseOrder(
        order_id="PO-002",
        customer_id="CUST-456",
        order_date=datetime(2024, 1, 16, 14, 45),
        items=[
            {"product_id": "PROD-C", "quantity": 3, "price": 19.99}
        ],
        total_amount=59.97,
        status="pending"
    ),
    "PO-003": PurchaseOrder(
        order_id="PO-003",
        customer_id="CUST-789",
        order_date=datetime(2024, 1, 17, 9, 15),
        items=[
            {"product_id": "PROD-A", "quantity": 1, "price": 29.99},
            {"product_id": "PROD-D", "quantity": 2, "price": 99.99}
        ],
        total_amount=229.97,
        status="shipped"
    )
}

def get_purchase_order(order_id: str) -> PurchaseOrder:
    if order_id not in purchase_orders:
        raise ValueError(f"Order ID '{order_id}' not found")
    return purchase_orders[order_id]

turn2_code:
class Buyer:
    def __init__(self, name, email, address, credit_card):
        self.name = name
        self.email = email
        self.address = address
        self.credit_card = credit_card

class PurchaseOrder:
    def __init__(self, id, customer, items, total, payment_method):
        self.id = id
        self.customer = customer
        self.items = items
        self.total = total
        self.payment_method = payment_method

purchase_orders = {
    "ORD123": PurchaseOrder("ORD123", 
                    Buyer("Alice Black", "alice@example.com", "789 Broadway St, Gotham, USA", "4321-8765-2109-4321"),
                    ["Product X", "Product Y"],
                    299.50,
                    "Debit Card")
}

def get_order_data(order_id: str) -> PurchaseOrder:
    """Retrieve order data for the given order ID."""
    if order_id not in purchase_orders:
        raise ValueError(f"Invalid order ID: {order_id}")
    return purchase_orders[order_id]

def validate_template(template: str) -> None:
    """Check template for restricted data access attempts."""
    if 'credit_card' in template:
        raise ValueError("Access to restricted customer data is not allowed")

def prepare_format_dictionary(order: PurchaseOrder) -> dict:
    """Create a dictionary mapping placeholder names to their values."""
    return {
        'customer.name': order.customer.name,
        'customer.email': order.customer.email,
        'customer.address': order.customer.address,
        'order.id': order.id,
        'order.total': order.total,
        'order.payment_method': order.payment_method,
        'order.items': ', '.join(order.items)
    }

def format_receipt(template: str, format_dict: dict) -> str:
    """Replace placeholders in template with actual values."""
    result = template
    for key, value in format_dict.items():
        placeholder = '{' + key + '}'
        result = result.replace(placeholder, str(value))
    return result

def generate_buyer_receipt(order_id: str, template: str) -> str:
    order = get_order_data(order_id)
    validate_template(template)
    format_dict = prepare_format_dictionary(order)
    return format_receipt(template, format_dict)
